INSERT INTO `wp_aioseo_notifications` (`id`, `slug`, `addon`, `title`, `content`, `type`, `level`, `notification_id`, `notification_name`, `start`, `end`, `button1_label`, `button1_action`, `button2_label`, `button2_action`, `dismissed`, `new`, `created`, `updated`) VALUES
(1, '68188b0e07688', NULL, 'Have you connected your site to Google Search Console?', 'AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.', 'warning', '[\"all\"]', NULL, 'search-console-site-not-connected', '2025-05-05 09:55:26', NULL, 'Connect to Google Search Console', 'https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole', NULL, NULL, 0, 0, '2025-05-05 09:55:26', '2025-05-05 09:55:26'),
(2, '682bea550313a', NULL, 'Laporan Email', 'Jadi yang terdepan di SEO dengan intisari email baru kami! Dapatkan petunjuk, tren, dan alat terbaru yang dikirim langsung ke kotak masuk Anda, membantu Anda mengoptimalkan dengan lebih tepat dan lebih cepat. Aktifkan sekarang dan jangan lewatkan pembaruan yang dapat meningkatkan peringkat Anda ke level selanjutnya.', 'info', '[\"all\"]', NULL, 'email-reports-enable-reminder', '2025-05-20 02:35:01', NULL, 'Aktifkan Laporan Email', 'https://route#aioseo-settings&aioseo-scroll=aioseo-email-summary-row&aioseo-highlight=aioseo-email-summary-row:advanced', 'Baik, saya sudah mengerti', 'http://action#notification/email-reports-enable', 0, 0, '2025-05-20 02:35:01', '2025-05-20 02:35:01');
