(2272, 1, '2025-05-09 04:15:50', '2025-05-09 04:15:50', '<!-- wp:image {\"id\":2232,\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Untitled-design-1024x576.png\" alt=\"\" class=\"wp-image-2232\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"width\":\"100%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:100%\"><!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#000000\"}}},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color has-link-color\" style=\"color:#000000\"><strong>Tasikmalaya, 30 April 2025</strong>Â â Pemerintah Kota (Pemkot) Tasikmalaya melalui Dinas Pekerjaan Umum dan Tata Ruang (PUTR) menyelenggarakan kegiatan Fasilitasi Sertifikasi Tenaga Kerja Konstruksi (TKK) Tahun Anggaran 2025 (TA 2025) untuk kualifikasi jabatan Operator dan Teknisi/Analis.Â </p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {\"verticalAlignment\":null} -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"30%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:30%\"><!-- wp:image {\"id\":2236,\"width\":\"326px\",\"height\":\"auto\",\"aspectRatio\":\"4/3\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/WhatsApp-Image-2025-04-30-at-11.41.38-1024x768.jpeg\" alt=\"\" class=\"wp-image-2236\" style=\"aspect-ratio:4/3;object-fit:cover;width:326px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:33.33%\"><!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#000000\"}}},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color has-link-color\" style=\"color:#000000\">Kegiatan ini diikuti oleh 51 peserta yang sebelumnya telah lolos verifikasi data administrasi dan prasyarat kompetensi awal, khususnya dalam jabatan Operator dan Teknisi/Analis. Sertifikasi ini menjadi langkah strategis guna meningkatkan profesionalisme dan kualitas layanan di sektor konstruksi, sekaligus memastikan tenaga kerja memenuhi standar nasional yang berlaku.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {\"verticalAlignment\":null} -->\n<div class=\"wp-block-columns\"><!-- wp:column {\"verticalAlignment\":\"top\",\"width\":\"30%\"} -->\n<div class=\"wp-block-column is-vertically-aligned-top\" style=\"flex-basis:30%\"><!-- wp:image {\"id\":2237,\"width\":\"326px\",\"height\":\"auto\",\"aspectRatio\":\"4/3\",\"scale\":\"cover\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/WhatsApp-Image-2025-04-30-at-11.41.35-1-1024x768.jpeg\" alt=\"\" class=\"wp-image-2237\" style=\"aspect-ratio:4/3;object-fit:cover;width:326px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column {\"width\":\"33.33%\"} -->\n<div class=\"wp-block-column\" style=\"flex-basis:33.33%\"><!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#000000\"}}},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color has-link-color\" style=\"color:#000000\">Acara dihadiri oleh Asisten Daerah , Staf Ahli Bidang Ekonomi dan Pembangunan, Ketua Komisi 3 DPRD Kota Tasikmalaya, PT Denicont Anugrah Pratama sebagai Lembaga Pelatihan Kerja (LPK) dan Badan Nasional Sertifikasi Profesi (BNSP) yang bertugas menguji kompetensi peserta. Ketua Komisi 3 DPRD Kota Tasikmalaya,Â <strong>Anang Sapaâat, S.SosÂ </strong>dalam sambutannyaÂ mengungkapkan bahwa komisi 3 akan mendorong penambahan anggaran untuk sertifikasi jasa konstruksi, hal ini dilakukan supaya target minimum 75 orang/tahun dapat tercapai, sesuai dengan surat edaran Kementrian PUPR, Dirjen Binamarga konstruksi yang telah disepakati bersama Kemendagri dan Bappenas, selain itu sambutan wali kota yang di wakili oleh staff ahli bidang ekonomi dan pembangunan,Â <strong>Budy Rachman, S.Sos.,M.Si</strong>Â juga memberikan sambutan, mewakili bapak wali kota sekaligus membuka acara, mengungkapkan bahwa kegiatan ini merupakan bagian dari komitmen Pemkot mendukung pembangunan infrastruktur berkelanjutan. âMelalui sertifikasi, kami ingin memastikan tenaga kerja konstruksi di Tasikmalaya mampu bersaing di tingkat regional maupun nasional,â ujarnya</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"flexWrap\":\"nowrap\"}} -->\n<div class=\"wp-block-group\"><!-- wp:image {\"id\":2238,\"width\":\"285px\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/WhatsApp-Image-2025-04-30-at-11.41.30-1024x768.jpeg\" alt=\"\" class=\"wp-image-2238\" style=\"width:285px\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image {\"id\":2239,\"width\":\"285px\",\"height\":\"auto\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/WhatsApp-Image-2025-04-30-at-11.41.31-1024x768.jpeg\" alt=\"\" class=\"wp-image-2239\" style=\"width:285px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:group -->\n\n<!-- wp:group {\"layout\":{\"type\":\"flex\",\"orientation\":\"vertical\"}} -->\n<div class=\"wp-block-group\"><!-- wp:image {\"id\":2240,\"width\":\"287px\",\"height\":\"auto\",\"sizeSlug\":\"large\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-large is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/WhatsApp-Image-2025-04-30-at-11.41.32-1024x768.jpeg\" alt=\"\" class=\"wp-image-2240\" style=\"width:287px;height:auto\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:group -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#000000\"}}},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color has-link-color\" style=\"color:#000000\">Proses sertifikasi diawali dengan verifikasi data peserta oleh panitia. Selanjutnya, peserta yang sudah diverifikasi oleh panitia mengikuti pembekalan dari LPK lalu mengikuti uji kompetensi dari sejumlah assesor dari BNSP.Â  Bagi yang lulus, mereka berhak mendapatkan Sertifikat Kompetensi Kerja (SKK) Konstruksi berbasis elektronik (E-Sertifikat) yang berlaku secara nasional.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#000000\"}}},\"color\":{\"text\":\"#000000\"}}} -->\n<p class=\"has-text-color has-link-color\" style=\"color:#000000\">Sertifikasi ini tidak hanya menjadi bukti kompetensi tenaga kerja, tetapi juga syarat hukum dalam pengajuan izin usaha konstruksi. Dengan meningkatnya kualitas SDM, diharapkan proyek-proyek konstruksi di Tasikmalaya dapat berjalan lebih efektif, aman, dan sesuai standar.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Dinas Pekerjaan Umum dan Tata Ruang Kota Tasikmalaya Fasilitasi Sertifikasi Tenaga Kerja Konstruksi untuk Tingkatkan Kompetensi SDM', '', 'publish', 'closed', 'open', '', 'dinas-pekerjaan-umum-dan-tata-ruang-kota-tasikmalaya-fasilitasi-sertifikasi-tenaga-kerja-konstruksi-untuk-tingkatkan-kompetensi-sdm-2', '', '', '2025-05-09 04:15:50', '2025-05-09 04:15:50', '', 0, 'https://pupr.tasikmalayakota.go.id/?p=2272', 0, 'post', '', 0);
