(2423, 1, '2019-04-01 14:32:16', '2019-04-01 14:32:16', '<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"id\":53,\"textAlignment\":\"left\",\"layout\":\"left\",\"marginRight\":\"70px\",\"mobileLayout\":\"column\",\"mobileAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-image-box has-image-left has-text-left has-mobile-layout-column has-mobile-alignment-center\"><div style=\"margin-right:70px\" class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://getwid.getmotopress.com/wp-content/uploads/2019/04/home_header-1.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-53\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/advanced-heading {\"textColor\":\"dark-blue\",\"titleTag\":\"h2\",\"fontFamily\":\"Work Sans\",\"fontSize\":\"48px\",\"fontWeight\":\"600\",\"lineHeight\":\"1em\",\"marginBottom\":\"30px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:48px;margin-bottom:30px\"><h2 class=\"wp-block-getwid-advanced-