wid-advanced-spacer\" style=\"height:20px\" aria-hidden=\"true\"></div>\n<!-- /wp:getwid/advanced-spacer -->\n\n<!-- wp:getwid/toggle {\"iconPosition\":\"right\",\"headerTag\":\"h6\"} -->\n<div class=\"wp-block-getwid-toggle\" data-active-element=\"0\"><div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><h6 class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">can i get free expert advice?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></h6></div><div class=\"wp-block-getwid-toggle__content\">If you already have the concept and design, you can request our free expert consultation and we\'ll get back to you within one week. If you need tech advice, you can book a premium one-hour consultation.</div></div><div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><h6 class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do i own the app?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></h6></div><div class=\"wp-block-getwid-toggle__content\">We take care of your ownership rights! You have the right to the app we develop for your business needs. You also own the bespoke design solutions we create according to your mockups and instructions.</div></div><div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><h6 class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do you restore broken software?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></h6></div><div class=\"wp-block-getwid-toggle__content\">We normally provide this service of restoring broken source code repositories. However, since this is the most time-consuming and challenging process, we need to firstly look through your particular problem.</div></div></div>\n<!-- /wp:getwid/toggle --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingTopValue\":\"40px\",\"paddingBottomValue\":\"40px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:40px;padding-bottom:40px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"backgroundImage\":{\"alt\":\"\",\"id\":387,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\"},\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\"} -->\n<div class=\"w