-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"textAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-advanced-heading\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">What People Say About Us </h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"28px\",\"fontWeight\":\"200\",\"fontStyle\":\"normal\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"textAlignment\":\"center\",\"marginTop\":\"5px\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:28px;margin-bottom:50px;margin-top:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center;font-family:&quot;Work Sans&quot;;font-weight:200;font-style:normal;line-height:1em;letter-spacing:0px\"> You Are in Good Hands</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns {\"className\":\"has-2-columns\"} -->\n<div class=\"wp-block-columns has-2-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/testimonial {\"imgId\":48} -->\n<div class=\"wp-block-getwid-testimonial has-image\"><div class=\"wp-block-getwid-testimonial__wrapper\"><div class=\"wp-block-getwid-testimonial__content-wrapper\"><p class=\"wp-block-getwid-testimonial__content\">I\'m happy with the result! We managed to run a startup app for connecting businesses with medical experts in order to streamline their communication.</p></div><div class=\"wp-block-getwid-testimonial__header\"><div class=\"wp-block-getwid-testimonial__image-wrapper\"><div class=\"wp-block-getwid-testimonial__image\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/testimonials_avatar1.jpg\" alt=\"\" class=\"wp-image-48\"/></div></div><div class=\"wp-block-getwid-testimonial__heading\"><span class=\"wp-block-getwid-testimonial__title\">Adam Smith </span><span cla