s-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/icons_service4.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-44\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:heading {\"level\":5,\"placeholder\":\"Write headingâ¦\"} -->\n<h5 class=\"wp-block-heading\">Startup Software</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>We help startups and ventures with the most challenging tech aspect of starting a project</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:getwid/image-box --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/image-box {\"id\":40,\"textAlignment\":\"left\",\"mobileLayout\":\"column\",\"mobileAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-image-box has-text-left has-mobile-layout-column has-mobile-alignment-center\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/icons_service5.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-40\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:heading {\"level\":5,\"placeholder\":\"Write headingâ¦\"} -->\n<h5 class=\"wp-block-heading\">White Label</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>We can help you build white label software solutions that you can license to your own clients </p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:getwid/image-box --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/image-box {\"id\":45,\"textAlignment\":\"left\",\"mobileLayout\":\"column\",\"mobileAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-image-box has-text-left has-mobile-layout-column has-mobile-alignment-center\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/icons_service6.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-45\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:heading {\"level\":5,\"placeholder\":\"Write headingâ¦\"} -->\n<h5 class=\"wp-block-heading\">Consultancy</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Our software consultants help define technology barriers to improve business tech aspects </p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:getwid/image-box --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingRightValue\":\"50%\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"id\":56,\"textAlignment\":\"left\",\"layout\":\"right\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box has-image-right has-text-left has-mobile-layout-column has-mobile-alignment-default\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_FAQ-1.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-56\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":510,\"gapSize\":\"\",\"horizontalAlign\":\"flex-end\",\"backgroundImage\":{\"alt\":\"\",\"id\":47,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\"},\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingTopValue\":\"90px\",\"paddingBottomValue\":\"90px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-justify-content-flex-end\" style=\"padding-top:90px;padding-bottom:90px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:510px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\');background-position:bottom left;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWeight\":\"200\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"marginBottom\":\"5px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:24px;margin-bottom:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"font-family:&quot;Work Sans&quot;;font-weight:200;line-height:1em;letter-spacing:0px\">Discover More</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"30px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:30px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Frequently Asked Questions</h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Still have questions? Learn more about our services and experience through the questions of people like you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:getwid/advanced-spacer {\"height\":\"20px\"} -->\n<div class=\"wp-block-getwid-advanced-spacer\" style=\"height:20px\" aria-hidden=\"true\"></div>\n<!-- /wp:getwid/advanced-spacer -->\n\n<!-- wp:getwid/toggle {\"iconPosition\":\"right\",\"headerTag\":\"h6\"} -->\n<div class=\"wp-block-getwid-toggle\"><!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">can i get free expert advice?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>If you already have the concept and design, you can request our free expert consultation and we\'ll get back to you within one week. If you need tech advice, you can book a premium one-hour consultation.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do i own the app?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>We take care of your ownership rights! You have the right to the app we develop for your business needs. You also own the bespoke design solutions we create according to your mockups and instructions.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do you restore broken software?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>We normally provide this service of restoring broken source code repositories. However, since this is the most time-consuming and challenging process, we need to firstly look through your particular problem.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item --></div>\n<!-- /wp:getwid/toggle --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingTopValue\":\"40px\",\"paddingBottomValue\":\"40px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:40px;padding-bottom:40px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"backgroundImage\":{\"alt\":\"\",\"id\":387,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\"},\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1130px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\');background-position:bottom right;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"textAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-advanced-heading\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">What People Say About Us </h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"28px\",\"fontWeight\":\"200\",\"fontStyle\":\"normal\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"textAlignment\":\"center\",\"marginTop\":\"5px\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:28px;margin-bottom:50px;margin-top:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center;font-family:&quot;Work Sans&quot;;font-weight:200;font-style:normal;line-height:1em;letter-spacing:0px\"> You Are in Good Hands</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns {\"className\":\"has-2-columns\"} -->\n<div class=\"wp-block-columns has-2-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/testimonial {\"imgId\":48} -->\n<div class=\"wp-block-getwid-testimonial has-image\"><div class=\"wp-block-getwid-testimonial__wrapper\"><div class=\"wp-block-getwid-testimonial__content-wrapper\"><p class=\"wp-block-getwid-testimonial__content\">I\'m happy with the result! We managed to run a startup app for connecting businesses with medical experts in order to streamline their communication.</p></div><div class=\"wp-block-getwid-testimonial__header\"><div class=\"wp-block-getwid-testimonial__image-wrapper\"><div class=\"wp-block-getwid-testimonial__image\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/testimonials_avatar1.jpg\" alt=\"\" class=\"wp-image-48\"/></div></div><div class=\"wp-block-getwid-testimonial__heading\"><span class=\"wp-block-getwid-testimonial__title\">Adam Smith </span><span class=\"wp-block-getwid-testimonial__subtitle\">Founder, BizzPro</span></div></div></div></div>\n<!-- /wp:getwid/testimonial --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/testimonial {\"imgId\":50} -->\n<div class=\"wp-block-getwid-testimonial has-image\"><div class=\"wp-block-getwid-testimonial__wrapper\"><div class=\"wp-block-getwid-testimonial__content-wrapper\"><p class=\"wp-block-getwid-testimonial__content\">Modern IT skills, the best-in-class designers and overall great people to deal with! We recommend it to every startup. We look up to these experts!</p></div><div class=\"wp-block-getwid-testimonial__header\"><div class=\"wp-block-getwid-testimonial__image-wrapper\"><div class=\"wp-block-getwid-testimonial__image\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/testimonials_avatar2.jpg\" alt=\"\" class=\"wp-image-50\"/></div></div><div class=\"wp-block-getwid-testimonial__heading\"><span class=\"wp-block-getwid-testimonial__title\">Tom Taylor</span><span class=\"wp-block-getwid-testimonial__subtitle\">Unicorn</span></div></div></div></div>\n<!-- /wp:getwid/testimonial --></div>\n<!-- /wp:column