</div>\n\n    <script>\n        // ... (script sebelumnya tetap dipertahankan) ...\n    </script>\n</body>\n</html>\n<!-- /wp:getwid/section -->', 'Pendataan Bangunan', '', 'inherit', 'closed', 'closed', '', '2469-revision-v1', '', '', '2025-05-06 03:29:36', '2025-05-06 03:29:36', '', 2469, 'http://localhost/wordpress/?p=2471', 0, 'revision', '', 0),
