:heading {\"level\":5,\"placeholder\":\"Write headingâ¦\"} -->\n<h5 class=\"wp-block-heading\">Data Migration</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>We\'ll create a safe information environment for data migration based on your current system<br></p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:getwid/image-box --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/image-box {\"id\":43,\"textAlignment\":\"left\",\"mobileLayout\":\"column\",\"mobileAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-image-box has-text-left has-mobile-layout-column has-mobile-alignment-center\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/icons_service3.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-43\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:heading {\"level\":5,\"placeholder\":\"Write headingâ¦\"} -->\n<h5 class=\"wp-block-heading\">CRM Systems</h5>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Improve your customer engagement with a bespoke, secure and dedicated CRM system <br></p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:getwid/image-box --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns {\"className\":\"has-3-columns\"} -->\n<div class=\"wp-block-columns has-3-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/image-box {\"id\":44,\"textAlignment\":\"left\",\"mobileLayout\":\"column\",\"mobileAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-image-box has-text-left has-mobile-layout-column has-mobile-alignment-center\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\