home_get-in-touch-points2.png\');background-position:top right;background-repeat:no-repeat;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_get-in-touch-points2.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"id\":329,\"textAlignment\":\"left\",\"layout\":\"left\",\"imagePosition\":\"middle\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box has-image-left has-text-left has-mobile-layout-column has-mobile-alignment-default\"><div class=\"wp-block-getwid-image-box__image-container is-position-middle\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_get-in-touch1.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-329\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":510,\"gapSize\":\"\",\"horizontalAlign\":\"flex-start\",\"paddingTop\":\"normal\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-normal getwid-justify-content-flex-start\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:510px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWei