(2493, 1, '2025-05-09 09:27:39', '2025-05-09 09:27:39', '<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":895,\"minHeight\":\"130px\",\"resetMinHeightTablet\":true,\"resetMinHeightMobile\":true,\"verticalAlign\":\"flex-start\",\"backgroundColor\":\"light-blue\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-align-items-flex-start getwid-reset-min-height-tablet getwid-reset-min-height-mobile\" style=\"min-height:130px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:895px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background has-background has-light-blue-background-color\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/images-slider {\"ids\":[1234,2478,2477],\"sliderAutoplay\":true,\"slideHeight\":\"500px\",\"resetHeightOnTablet\":true,\"resetHeightOnMobile\":true} -->\n<div class=\"wp-block-getwid-images-slider has-arrows-inside has-dots-inside has-images-center has-cropped-images has-fixed-height\"><div class=\"wp-block-getwid-images-slider__wrapper\" data-effect=\"slide\" data-slides-show=\"1\" data-slides-show-laptop=\"1\" data-slides-show-tablet=\"1\" data-slides-show-mobile=\"1\" data-slides-scroll=\"1\" data-autoplay=\"true\" data-pause-hover=\"false\" data-autoplay-speed=\"6000\" data-infinite=\"true\" data-animation-speed=\"800\" data-center-mode=\"false\" data-variable-width=\"false\" data-arrows=\"inside\" data-dots=\"inside\" data-spacing=\"none\"><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design.png\" data-id=\"1234\" data-link=\"https://dputr.tasikmalayakota.go.id/wordpress/?attachment_id=1234\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design.png\" class=\"wp-block-getwid-images-slider__image wp-image-1234\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-1-1.png\" data-id=\"2478\" data-link=\"https://dputr.tasikmalayakota.go.id/wordpress/?attachment_id=2478\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-1-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2478\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-1.png\" data-id=\"2477\" data-link=\"https://dputr.tasikmalayakota.go.id/wordpress/?attachment_id=2477\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2477\"/></figure></div></div></div>\n<!-- /wp:getwid/images-slider --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"gapSize\":\"\",\"backgroundGradientFirstColor\":\"#ffffff\",\"backgroundGradientSecondColor\":\"#f7fbfe\",\"backgroundGradientType\":\"linear\",\"paddingTopValue\":\"50px\",\"paddingBottomValue\":\"50px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\"} -->\n<div id=\"learn-more\" class=\"wp-block-getwid-section alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:50px;padding-bottom:50px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1130px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:linear-gradient(180deg,rgba(255,255,255) 0%,rgba(247,251,254) 100%)\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\",\"paddingBottomValue\":\"30px\",\"paddingTop\":\"none\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\",\"marginBottomValue\":\"40px\",\"marginBottom\":\"custom\",\"className\":\"has-inner-blocks-gap-undefined\"} -->\n<div class=\"wp-block-getwid-section has-inner-blocks-gap-undefined\" style=\"margin-bottom:40px\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-left-none getwid-padding-right-none\" style=\"padding-bottom:30px\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontWeight\":\"\",\"textAlignment\":\"center\",\"marginBottom\":\"10px\"} -->\n<div class=\"wp-block-getwid-advanced-heading\" style=\"margin-bottom:10px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">Tentang Kami</h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":760,\"paddingTop\":\"none\",\"paddingBottom\":\"none\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-bottom-none getwid-padding-left-none getwid-padding-right-none\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:760px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Dinas Pekerjaan Umum dan Tata Ruang (PUTR) Kota Tasikmalaya</strong> adalah salah satu perangkat daerah di lingkungan Pemerintah Kota Tasikmalaya yang bertanggung jawab terhadap pembangunan fisik kota, pengelolaan infrastruktur, serta perencanaan tata ruang agar Kota Tasikmalaya dapat tumbuh secara teratur, efisien, dan berkelanjutan.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"45px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:45px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Unit Kerja </h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns {\"className\":\"has-3-columns\"} -->\n<div class=\"wp-block-columns has-3-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:blockart/image {\"clientId\":\"fcc23cda\",\"image\":{\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled_design__2_-removebg-preview.png\",\"id\":2484,\"height\":200,\"width\":200,\"alt\":\"\"},\"width\":{\"desktop\":{\"value\":252,\"unit\":\"px\"}}} -->\n<figure class=\"blockart-image blockart-image-fcc23cda\"><img class=\"wp-image-2484 hover-effect-static filter-none mask mask-none\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled_design__2_-removebg-preview.png\" alt=\"\" height=\"200\" width=\"200\"/></figure>\n<!-- /wp:blockart/image -->\n\n<!-- wp:paragraph -->\n<p><br><br>Sekretariat mempunyai tugas pokok memberikan<br>pelayanan administratif, pengendalian dalam <br>koordinasi pelaksanaan dan kegiatan <br>kesekretariatan yang meliputi perencanaan,<br>pengelolaan kepegawaian, pengelolaan keuangan<br>dan barang milik daerah, penataan organisasi dan<br>administrasi umum.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:blockart/image {\"clientId\":\"d4360bf9\",\"image\":{\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-2.png\",\"id\":2490,\"height\":200,\"width\":200,\"alt\":\"\"},\"width\":{\"desktop\":{\"value\":252,\"unit\":\"px\"}},\"height\":{\"desktop\":{\"value\":310,\"unit\":\"px\"}}} -->\n<figure class=\"blockart-image blockart-image-d4360bf9\"><img class=\"wp-image-2490 hover-effect-static filter-none mask mask-none\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/05/Untitled-design-2.png\" alt=\"\" height=\"200\" width=\"200\"/></figure>\n<!-- /wp:blockart/image -->\n\n<!-- wp:paragraph -->\n<p>Bidang Tata Ruang dan Pertanahan mempunyai<br>tugas pokok menyelenggarakan penyusunan bahan<br>kebijakan teknis dan menyelenggarakan kebijakan<br>teknis perencanaan tata ruang, pemanfaatan<br>pengendalian tata ruang, pelayanan data dan<br>informasi tata ruang serta pertanahan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:blockart/image {\"clientId\":\"d01216d7\",\"image\":{\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\",\"id\":1149,\"height\":224,\"width\":225,\"alt\":\"\"}} -->\n<figure class=\"blockart-image blockart-image-d01216d7\"><img class=\"wp-image-1149 hover-effect-static filter-none mask mask-none\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\" alt=\"\" height=\"224\" width=\"225\"/></figure>\n<!-- /wp:blockart/image -->\n\n<!-- wp:paragraph -->\n<p>Bidang Tata Bangunan dan Jasa Konstruksi<br>mempunyai tugas pokok menyelenggarakan<br>penyusunan bahan kebijakan teknis<br>dan menyelenggarakan kebijakan<br>penataan bangunan gedung, penataan <br>bangunan dan lingkungannya serta<br>pembinaan konstruksi.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:blockart/image {\"clientId\":\"fd2ed03a\",\"image\":{\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\",\"id\":1149,\"height\":224,\"width\":225,\"alt\":\"\"}} -->\n<figure class=\"blockart-image blockart-image-fd2ed03a\"><img class=\"wp-image-1149 hover-effect-static filter-none mask mask-none\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\" alt=\"\" height=\"224\" width=\"225\"/></figure>\n<!-- /wp:blockart/image -->\n\n<!-- wp:paragraph -->\n<p>Bidang Sumber Daya Air mempunyai tugas pokok<br>menyelenggarakan penyusunan bahan kebijakan<br>teknis, pembangunan/pengelolaan sumber daya air<br>serta pembinaan, pengawasan dan pengendalian<br>pengelolaan sumber daya air.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingRightValue\":\"50%\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"id\":56,\"textAlignment\":\"left\",\"layout\":\"right\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box has-image-right has-text-left has-mobile-layout-column has-mobile-alignment-default\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_FAQ-1.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-56\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":510,\"gapSize\":\"\",\"horizontalAlign\":\"flex-end\",\"backgroundImage\":{\"alt\":\"\",\"id\":47,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\"},\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingTopValue\":\"90px\",\"paddingBottomValue\":\"90px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-justify-content-flex-end\" style=\"padding-top:90px;padding-bottom:90px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:510px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\');background-position:bottom left;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWeight\":\"200\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"marginBottom\":\"5px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:24px;margin-bottom:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"font-family:&quot;Work Sans&quot;;font-weight:200;line-height:1em;letter-spacing:0px\">Discover More</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"30px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:30px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Frequently Asked Questions</h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Still have questions? Learn more about our services and experience through the questions of people like you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:getwid/advanced-spacer {\"height\":\"20px\"} -->\n<div class=\"wp-block-getwid-advanced-spacer\" style=\"height:20px\" aria-hidden=\"true\"></div>\n<!-- /wp:getwid/advanced-spacer -->\n\n<!-- wp:getwid/toggle {\"iconPosition\":\"right\",\"headerTag\":\"h6\"} -->\n<div class=\"wp-block-getwid-toggle\"><!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">can i get free expert advice?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>If you already have the concept and design, you can request our free expert consultation and we\'ll get back to you within one week. If you need tech advice, you can book a premium one-hour consultation.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do i own the app?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>We take care of your ownership rights! You have the right to the app we develop for your business needs. You also own the bespoke design solutions we create according to your mockups and instructions.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">do you restore broken software?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>We normally provide this service of restoring broken source code repositories. However, since this is the most time-consuming and challenging process, we need to firstly look through your particular problem.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item --></div>\n<!-- /wp:getwid/toggle --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingTopValue\":\"40px\",\"paddingBottomValue\":\"40px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:40px;padding-bottom:40px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"backgroundImage\":{\"alt\":\"\",\"id\":387,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\"},\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1130px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\');background-position:bottom right;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_testimonials_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"textAlignment\":\"center\"} -->\n<div class=\"wp-block-getwid-advanced-heading\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">What People Say About Us </h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"28px\",\"fontWeight\":\"200\",\"fontStyle\":\"normal\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"textAlignment\":\"center\",\"marginTop\":\"5px\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:28px;margin-bottom:50px;margin-top:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center;font-family:&quot;Work Sans&quot;;font-weight:200;font-style:normal;line-height:1em;letter-spacing:0px\"> You Are in Good Hands</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns {\"className\":\"has-2-columns\"} -->\n<div class=\"wp-block-columns has-2-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/testimonial {\"imgId\":48} -->\n<div class=\"wp-block-getwid-testimonial has-image\"><div class=\"wp-block-getwid-testimonial__wrapper\"><div class=\"wp-block-getwid-testimonial__content-wrapper\"><p class=\"wp-block-getwid-testimonial__content\">I\'m happy with the result! We managed to run a startup app for connecting businesses with medical experts in order to streamline their communication.</p></div><div class=\"wp-block-getwid-testimonial__header\"><div class=\"wp-block-getwid-testimonial__image-wrapper\"><div class=\"wp-block-getwid-testimonial__image\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/testimonials_avatar1.jpg\" alt=\"\" class=\"wp-image-48\"/></div></div><div class=\"wp-block-getwid-testimonial__heading\"><span class=\"wp-block-getwid-testimonial__title\">Adam Smith </span><span class=\"wp-block-getwid-testimonial__subtitle\">Founder, BizzPro</span></div></div></div></div>\n<!-- /wp:getwid/testimonial --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:getwid/testimonial {\"imgId\":50} -->\n<div class=\"wp-block-getwid-testimonial has-image\"><div class=\"wp-block-getwid-testimonial__wrapper\"><div class=\"wp-block-getwid-testimonial__content-wrapper\"><p class=\"wp-block-getwid-testimonial__content\">Modern IT skills, the best-in-class designers and overall great people to deal with! We recommend it to every startup. We look up to these experts!</p></div><div class=\"wp-block-getwid-testimonial__header\"><div class=\"wp-block-getwid-testimonial__image-wrapper\"><div class=\"wp-block-getwid-testimonial__image\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/testimonials_avatar2.jpg\" alt=\"\" class=\"wp-image-50\"/></div></div><div class=\"wp-block-getwid-testimonial__heading\"><span cla