ne getwid-padding-left-none getwid-padding-right-none\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_get-in-touch-points2.png\');background-position:top right;background-repeat:no-repeat;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_get-in-touch-points2.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"id\":329,\"textAlignment\":\"left\",\"layout\":\"left\",\"imagePosition\":\"middle\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box has-image-left has-text-left has-mobile-layout-column has-mobile-alignment-default\"><div class=\"wp-block-getwid-image-box__image-container is-position-middle\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_get-in-touch1.png\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-329\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":510,\"gapSize\":\"\",\"horizontalAlign\":\"flex-start\",\"paddingTop\":\"normal\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-normal getwid-justify-content-flex-start\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:510px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWeight\":\"200\",\"lineHeight\":\"1em\",\"marginBottom\":\"5px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:24px;margin-bottom:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"font-family:&quot;Work Sans&quot;;font-weight:200;line-height:1em\">Get in Touch</span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:50px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Have a Question? </h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/contact-form -->\n<!-- wp:getwid/field-name {\"label\":\"Name\",\"required\":true} /-->\n\n<!-- wp:getwid/field-email {\"label\":\"Email\",\"required\":true} /-->\n\n<!-- wp:getwid/field-textarea {\"required\":true} /-->\n<!-- /wp:getwid/contact-form --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:blockart/paragraph {\"clientId\":\"e945419c\"} /-->', 'Home', '', 'inherit', 'closed', 'closed', '', '2404-revision-v1', '', '', '2025-05-15 08:36:22', '2025-05-15 08:36:22', '', 2404, 'http://localhost/wordpress/?p=2501', 0, 'revision', '', 0),
