(2693, 1, '2025-05-27 01:31:57', '2025-05-27 01:31:57', '<!-- wp:getwid/section {\"skipLayout\":true} -->\n<div class=\"wp-block-getwid-section\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:html -->\n<article>\n  <h2>ð Memahami Indikator Kinerja Utama (IKU)</h2>\n  <p>\n    Dalam penyelenggaraan pemerintahan dan pelayanan publik, setiap instansi wajib memiliki tolok ukur untuk menilai keberhasilan pelaksanaan tugas dan fungsinya. Di sinilah peran <strong>Indikator Kinerja Utama (IKU)</strong> menjadi sangat penting.\n  </p>\n\n  <h3>ð Apa Itu IKU?</h3>\n  <p>\n    <strong>Indikator Kinerja Utama (IKU)</strong> adalah ukuran yang digunakan untuk menilai capaian kinerja suatu instansi pemerintah terhadap sasaran strategisnya. IKU menjadi alat untuk memastikan bahwa program dan kegiatan yang dilakukan benar-benar berdampak dan mendukung tujuan organisasi.\n  </p>\n\n  <h3>ð¯ Tujuan Penyusunan IKU</h3>\n  <ul>\n    <li>âINSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(2722, 1, '2025-05-27 08:03:41', '2025-05-27 08:03:41', '<!-- wp:getwid/section {\"skipLayout\":true} -->\n<div class=\"wp-block-getwid-section\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:html -->\n<section style=\"font-family: Arial, sans-serif; line-height: 1.6; max-width: 900px; margin: auto;\">\n  <h2 style=\"text-align: center; color: #2a7ae2;\">ð Apa Itu Standar Pelayanan?</h2>\n  <p><strong>Standar Pelayanan (SP)</strong> adalah tolok ukur resmi yang digunakan sebagai pedoman dalam penyelenggaraan pelayanan publik. Standar ini menetapkan hak dan kewajiban penyelenggara dan penerima layanan secara transparan, akuntabel, dan berorientasi pada kepuasan masyarakat.</p>\n\n  <p>Dalam praktiknya, SP membantu instansi publik untuk memberikan layanan yang <strong>berkualitas, konsisten, efisien, dan sesuai kebutuhan masyarakat</strong>. Dengan standar ini, masyarakat mendapatkan kejelasan tentang proses, biaya, waktu, dan kualitas layanan yang mereka terima.</p>\n\n  <h3>ð Komponen Umum Standar Pelayanan</h3>\n  <ul>\n    <li><strong>Jenis Layanan</strong> â Jenis layanan yang disediakan.</li>\n    <li><strong>Dasar Hukum</strong> â Peraturan yang mendasari layanan.</li>\n    <li><strong>Persyaratan</strong> â Dokumen/kondisi yang harus dipenuhi pengguna.</li>\n    <li><strong>Mekanisme & Prosedur</strong> â Langkah-langkah dari awal hingga akhir.</li>\n    <li><strong>Jangka Waktu</strong> â Lama pelayanan diberikan.</li>\n    <li><strong>Biaya/Tarif</strong> â Jumlah biaya (jika ada).</li>\n    <li><strong>Produk Layanan</strong> â Hasil atau output layanan.</li>\n    <li><strong>Sarana & Prasarana</strong> â Dukungan alat dan fasilitas.</li>\n    <li><strong>Kompetensi Pelaksana</strong> â Kualifikasi petugas layanan.</li>\n    <li><strong>Pengaduan & Evaluasi</strong> â Mekanisme keluhan dan penilaian layanan.</li>\n  </ul>\n\n  <p><em>Standar Pelayanan bukan hanya alat kontrol internal, tetapi juga komitmen untuk memberikan pelayanan terbaik kepada masyarakat.</em></p>\n\n  \n</section>\n<!-- /wp:html --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"skipLayout\":true} -->\n<div class=\"wp-block-getwid-section\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/recent-posts {\"categories\":\"50\",\"postsToShow\":3,\"showContent\":true,\"contentLength\":7,\"showFeaturedImage\":true} /--></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Standar Pelayanan', '', 'publish', 'closed', 'closed', '', 'standar-pelayanan', '', '', '2025-06-10 02:03:06', '2025-06-10 02:03:06', '', 0, 'http://localhost/wordpress/?page_id=2722', 0, 'page', '', 0),
