setHeightOnTablet\":true,\"resetHeightOnMobile\":true} -->\n<div class=\"wp-block-getwid-images-slider has-arrows-inside has-dots-inside has-images-center has-cropped-images has-fixed-height\"><div class=\"wp-block-getwid-images-slider__wrapper\" data-effect=\"slide\" data-slides-show=\"1\" data-slides-show-laptop=\"1\" data-slides-show-tablet=\"1\" data-slides-show-mobile=\"1\" data-slides-scroll=\"1\" data-autoplay=\"true\" data-pause-hover=\"false\" data-autoplay-speed=\"6000\" data-infinite=\"true\" data-animation-speed=\"800\" data-center-mode=\"false\" data-variable-width=\"false\" data-arrows=\"inside\" data-dots=\"inside\" data-spacing=\"none\"><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design.png\" data-id=\"1234\" data-link=\"https://dputr.tasikmalayakota.go.id/untitled-design/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design.png\" class=\"wp-block-getwid-images-slider__image wp-image-1234\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-1.png\" data-id=\"2478\" data-link=\"https://dputr.tasikmalayakota.go.id/home-2/untitled-design-1/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2478\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1.png\" data-id=\"2477\" data-link=\"https://dputr.tasikmalayakota.go.id/home-2/untitled-design-2/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2477\"/></figure></div></div></div>\n<!-- /wp:getwid/images-slider --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"boxed\",\"contentMaxWidth\":1130,\"gapSize\":\"\",\"backgroundGradientFirstColor\":\"#ffffff\",\"backgroundGradientSecondColor\":\"#f7fbfe\",\"backgroundGradientType\":\"linear\",\"paddingTopValue\":\"50px\",\"paddingBottomValue\":\"50px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\"} -->\n<div id=\"learn-more\" class=\"wp-block-getwid-section alignfull\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:50px;padding-bottom:50px\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:linear-gradient(180deg,rgba(255,255,255) 0%,rgba(247,251,254) 100%)\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\",\"paddingBottomValue\":\"30px\",\"paddingTop\":\"none\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\",\"marginBottomValue\":\"40px\",\"marginBottom\":\"custom\",\"className\":\"has-inner-blocks-gap-undefined\"} -->\n<div class=\"wp-block-getwid-section has-inner-blocks-gap-undefined\" style=\"margin-bottom:40px\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-left-none getwid-padding-right-none\" style=\"padding-bottom:30px\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontWeight\":\"\",\"textAlignment\":\"center\",\"marginBottom\":\"10px\"} -->\n<div class=\"wp-block-getwid-advanced-heading\" style=\"margin-bottom:10px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">Tentang Kami</h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":760,\"paddingTop\":\"none\",\"paddingBottom\":\"none\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-bottom-none getwid-padding-left-none getwid-padding-right-none\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:760px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Dinas Pekerjaan Umum dan Tata Ruang (PUTR) Kota Tasikmalaya</strong> adalah salah satu perangkat daerah di lingkungan Pemerintah Kota Tasikmalaya yang bertanggung jawab terhadap pembangunan fisik kota, pengelolaan infrastruktur, serta perencanaan tata ruang agar Kota Tasikmalaya dapat tumbuh secara teratur, efisien, dan berkelanjutan.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"45px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:45px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Unit Kerja </h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2484,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled_design__2_-removebg-preview.png\" alt=\"\" class=\"wp-image-2484\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2490,\"width\":\"232px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-2.png\" alt=\"\" class=\"wp-image-2490\" style=\"width:232px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Sekretariat mempunyai tugas pokok memberikan<br>pelayanan administratif, pengendalian dalam <br>koordinasi pelaksanaan dan kegiatan <br>kesekretariatan yang meliputi perencanaan,<br>pengelolaan kepegawaian, pengelolaan keuangan<br>dan barang milik daerah, penataan organisasi dan<br>administrasi umum.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Tata Ruang dan Pertanahan mempunyai<br>tugas pokok menyelenggarakan penyusunan bahan<br>kebijakan teknis dan menyelenggarakan kebijakan<br>teknis perencanaan tata ruang, pemanfaatan<br>pengendalian tata ruang, pelayanan data dan<br>informasi tata ruang serta pertanahan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2504,\"width\":\"239px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-2.png\" alt=\"\" class=\"wp-image-2504\" style=\"width:239px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2506,\"width\":\"224px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-4.png\" alt=\"\" class=\"wp-image-2506\" style=\"width:224px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Tata Bangunan dan Jasa Konstruksi<br>mempunyai tugas pokok menyelenggarakan<br>penyusunan bahan kebijakan teknis<br>dan menyelenggarakan kebijakan<br>penataan bangunan gedung, penataan <br>bangunan dan lingkungannya serta<br>pembinaan konstruksi.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Sumber Daya Air mempunyai tugas pokok<br>menyelenggarakan penyusunan bahan kebijakan<br>teknis, pembangunan/pengelolaan sumber daya air<br>serta pembinaan, pengawasan dan pengendalian<br>pengelolaan sumber daya air.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><br><br></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2503,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-2-1.png\" alt=\"\" class=\"wp-image-2503\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2502,\"width\":\"258px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-3.png\" alt=\"\" class=\"wp-image-2502\" style=\"width:258px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:getwid/section {\"skipLayout\":true} -->\n<div class=\"wp-block-getwid-section\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Jalan dan Jembatan mempunyai tugas pokok<br>menyelenggarakan penyusunan bahan kebijakan<br>teknis serta menyelenggarakan kegiatan<br>pembangunan, pemeliharaan dan pengelolaan<br>prasarana jalan dan jembatan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Permukiman mempunyai tugas pokok<br>menyelenggarakan penyusunan kebijakan teknis dan<br>menyelenggarakan kebijakan Bidang Permukiman<br>meliputi pengembangan Permukiman, pengelolaan<br>dan pengembangan sistem air limbah, pengelolaan<br>dan pengembangan sistem penyediaan air minum<br>serta<br>pengembangan sistem dan pengelolaan<br>persampahan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingRightValue\":\"50%\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"imageSize\":\"thumbnail\",\"id\":1149,\"textAlignment\":\"left\",\"layout\":\"right\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box getwid-animation has-image-right has-text-left has-mobile-layout-column has-mobile-alignment-default\" data-animation=\"wobble\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-1149\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":567,\"gapSize\":\"\",\"verticalAlign\":\"flex-end\",\"horizontalAlign\":\"flex-start\",\"backgroundImage\":{\"alt\":\"\",\"id\":47,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\"},\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingTopValue\":\"90px\",\"paddingBottomValue\":\"90px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-align-items-flex-end getwid-justify-content-flex-start\" style=\"padding-top:90px;padding-bottom:90px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:567px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\');background-position:bottom left;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWeight\":\"200\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"marginBottom\":\"5px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:24px;margin-bottom:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"font-family:&quot;Work Sans&quot;;font-weight:200;line-height:1em;letter-spacing:0px\">Temukan lebih </span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"30px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:30px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Frequently Asked Questions</h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Masih punya pertanyaan? pelajari lebih tentang pelayanan kami pada FAQ dibawah ini</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:getwid/advanced-spacer {\"height\":\"20px\"} -->\n<div class=\"wp-block-getwid-advanced-spacer\" style=\"height:20px\" aria-hidden=\"true\"></div>\n<!-- /wp:getwid/advanced-spacer -->\n\n<!-- wp:getwid/toggle {\"iconPosition\":\"right\",\"headerTag\":\"h6\"} -->\n<div class=\"wp-block-getwid-toggle\"><!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Bagaimana cara mengurus Sertifikat layak fungsi (Self) atau Persetujuan Bangunan Gedung (PBG)?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li> Anda dapat mengajukan permohonan   melalui sistem OSS (Online Single Submission)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Syarat umum: dokumen kepemilikan tanah, gambar teknis bangunan, KTP pemohon, dan pernyataan kesesuaian tata ruang.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apa yang dimaksud dengan Kesesuaian Kegiatan Pemanfaatan Ruang (KKPR)?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>KKPR adalah dokumen perizinan yang menyatakan bahwa suatu kegiatan/usaha sesuai dengan rencana tata ruang wilayah setempat.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Bagaimana cara mengetahui apakah tanah saya masuk kawasan yang boleh dibangun?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Anda perlu memeriksa <strong>Rencana Tata Ruang Wilayah (RTRW)</strong> atau <strong>RDTR (Rencana Detail Tata Ruang)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bisa dicek melalui Mall Pelayanan Publik yang ada di Bale Kota di bagian loket Dinas Pekerjaan Umum dan Tata Ruang</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Siapa yang bertanggung jawab atas saluran drainase yang tersumbat?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Tergantung Lokasi<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Drainase lingkungan: tanggung jawab warga/pemkot dalam hal ini adalah Dinas Pekerjaan Umum dan Tata Ruang bidang Sumber Daya Air</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Drainase utama: Dinas Pekerjaan Umum dan Tata Ruang bidang sumber daya air</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apakah Dinas Pekerjaan Umum dan Tata Ruang bisa membantu penyediaan air bersih</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Dinas Pekerjaan  Umum dan Tata Ruang  bertanggung jawab dalam pengelolaan jaringan air baku dan sanitasi, sementara distribusi air bersih biasanya oleh PDAM.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apa peran Dinas Pekerjaan Umum dan Tata Ruang dalam pembangunan infrastruktur?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>DPUTR bertanggung jawab atas perencanaan, pelaksanaan, dan pengawasan pembangunan infrastruktur seperti:<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Jalan dan jembatan</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Irigasi dan drainase</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Permukiman</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Penataan ruang dan pengendalian bangunan</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item --></div>\n<!-- /wp:getwid/toggle --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"gapSize\":\"\",\"backgroundGradientFirstColor\":\"#f7fbfe\",\"backgroundGradientSecondColor\":\"#ffffff\",\"backgroundGradientType\":\"linear\",\"paddingTopValue\":\"120px\",\"paddingBottomValue\":\"70px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:120px;padding-bottom:70px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1130px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:linear-gradient(180deg,rgba(247,251,254) 0%,rgba(255,255,255) 100%)\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:50px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">INFORMASI</h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/recent-posts {\"imageSize\":\"post-thumbnail\",\"cropImages\":false,\"categories\":\"49\",\"postsToShow\":3,\"showContent\":true,\"contentLength\":23,\"showFeaturedImage\":true,\"postLayout\":\"grid\"} /--></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '2404-revision-v1', '', '', '2025-08-11 03:59:43', '2025-08-11 03:59:43', '', 2404, 'https://dputr.tasikmalayakota.go.id/?p=2773', 0, 'revision', '', 0);
INSERT INTO `wp_posts` (`ID`, `post_author`, `post_date`, `post_date_gmt`, `post_content`, `post_title`, `post_excerpt`, `post_status`, `comment_status`, `ping_status`, `post_password`, `post_name`, `to_ping`, `pinged`, `post_modified`, `post_modified_gmt`, `post_content_filtered`, `post_parent`, `guid`, `menu_order`, `post_type`, `post_mime_type`, `comment_count`) VALUES
(2774, 1, '2025-08-11 04:00:04', '2025-08-11 04:00:04', '<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":895,\"minHeight\":\"130px\",\"resetMinHeightTablet\":true,\"resetMinHeightMobile\":true,\"verticalAlign\":\"flex-start\",\"backgroundColor\":\"light-blue\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-align-items-flex-start getwid-reset-min-height-tablet getwid-reset-min-height-mobile\" style=\"min-height:130px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:895px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background has-background has-light-blue-background-color\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/images-slider {\"ids\":[1234,2478,2477],\"sliderAutoplay\":true,\"slideHeight\":\"500px\",\"resetHeightOnTablet\":true,\"resetHeightOnMobile\":true} -->\n<div class=\"wp-block-getwid-images-slider has-arrows-inside has-dots-inside has-images-center has-cropped-images has-fixed-height\"><div class=\"wp-block-getwid-images-slider__wrapper\" data-effect=\"slide\" data-slides-show=\"1\" data-slides-show-laptop=\"1\" data-slides-show-tablet=\"1\" data-slides-show-mobile=\"1\" data-slides-scroll=\"1\" data-autoplay=\"true\" data-pause-hover=\"false\" data-autoplay-speed=\"6000\" data-infinite=\"true\" data-animation-speed=\"800\" data-center-mode=\"false\" data-variable-width=\"false\" data-arrows=\"inside\" data-dots=\"inside\" data-spacing=\"none\"><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design.png\" data-id=\"1234\" data-link=\"https://dputr.tasikmalayakota.go.id/untitled-design/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design.png\" class=\"wp-block-getwid-images-slider__image wp-image-1234\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-1.png\" data-id=\"2478\" data-link=\"https://dputr.tasikmalayakota.go.id/home-2/untitled-design-1/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2478\"/></figure></div><div class=\"wp-block-getwid-images-slider__item getwid-reset-height-tablet getwid-reset-height-mobile\" style=\"height:500px\"><figure><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1.png\" data-id=\"2477\" data-link=\"https://dputr.tasikmalayakota.go.id/home-2/untitled-design-2/\" data-original-link=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1.png\" class=\"wp-block-getwid-images-slider__image wp-image-2477\"/></figure></div></div></div>\n<!-- /wp:getwid/images-slider --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"boxed\",\"contentMaxWidth\":1130,\"gapSize\":\"\",\"backgroundGradientFirstColor\":\"#ffffff\",\"backgroundGradientSecondColor\":\"#f7fbfe\",\"backgroundGradientType\":\"linear\",\"paddingTopValue\":\"50px\",\"paddingBottomValue\":\"50px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\"} -->\n<div id=\"learn-more\" class=\"wp-block-getwid-section alignfull\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:50px;padding-bottom:50px\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:linear-gradient(180deg,rgba(255,255,255) 0%,rgba(247,251,254) 100%)\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/section {\"skipLayout\":true,\"backgroundImagePosition\":\"bottom right\",\"backgroundImageSize\":\"auto\",\"paddingBottomValue\":\"30px\",\"paddingTop\":\"none\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\",\"marginBottomValue\":\"40px\",\"marginBottom\":\"custom\",\"className\":\"has-inner-blocks-gap-undefined\"} -->\n<div class=\"wp-block-getwid-section has-inner-blocks-gap-undefined\" style=\"margin-bottom:40px\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-left-none getwid-padding-right-none\" style=\"padding-bottom:30px\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontWeight\":\"\",\"textAlignment\":\"center\",\"marginBottom\":\"10px\"} -->\n<div class=\"wp-block-getwid-advanced-heading\" style=\"margin-bottom:10px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"text-align:center\">Tentang Kami</h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":760,\"paddingTop\":\"none\",\"paddingBottom\":\"none\",\"paddingLeft\":\"none\",\"paddingRight\":\"none\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-top-none getwid-padding-bottom-none getwid-padding-left-none getwid-padding-right-none\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:760px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:paragraph {\"align\":\"center\"} -->\n<p class=\"has-text-align-center\"><strong>Dinas Pekerjaan Umum dan Tata Ruang (PUTR) Kota Tasikmalaya</strong> adalah salah satu perangkat daerah di lingkungan Pemerintah Kota Tasikmalaya yang bertanggung jawab terhadap pembangunan fisik kota, pengelolaan infrastruktur, serta perencanaan tata ruang agar Kota Tasikmalaya dapat tumbuh secara teratur, efisien, dan berkelanjutan.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"45px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:45px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Unit Kerja </h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2484,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled_design__2_-removebg-preview.png\" alt=\"\" class=\"wp-image-2484\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2490,\"width\":\"232px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-2.png\" alt=\"\" class=\"wp-image-2490\" style=\"width:232px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Sekretariat mempunyai tugas pokok memberikan<br>pelayanan administratif, pengendalian dalam <br>koordinasi pelaksanaan dan kegiatan <br>kesekretariatan yang meliputi perencanaan,<br>pengelolaan kepegawaian, pengelolaan keuangan<br>dan barang milik daerah, penataan organisasi dan<br>administrasi umum.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Tata Ruang dan Pertanahan mempunyai<br>tugas pokok menyelenggarakan penyusunan bahan<br>kebijakan teknis dan menyelenggarakan kebijakan<br>teknis perencanaan tata ruang, pemanfaatan<br>pengendalian tata ruang, pelayanan data dan<br>informasi tata ruang serta pertanahan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2504,\"width\":\"239px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-1-2.png\" alt=\"\" class=\"wp-image-2504\" style=\"width:239px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2506,\"width\":\"224px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-4.png\" alt=\"\" class=\"wp-image-2506\" style=\"width:224px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Tata Bangunan dan Jasa Konstruksi<br>mempunyai tugas pokok menyelenggarakan<br>penyusunan bahan kebijakan teknis<br>dan menyelenggarakan kebijakan<br>penataan bangunan gedung, penataan <br>bangunan dan lingkungannya serta<br>pembinaan konstruksi.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Sumber Daya Air mempunyai tugas pokok<br>menyelenggarakan penyusunan bahan kebijakan<br>teknis, pembangunan/pengelolaan sumber daya air<br>serta pembinaan, pengawasan dan pengendalian<br>pengelolaan sumber daya air.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><br><br></p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2503,\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-2-1.png\" alt=\"\" class=\"wp-image-2503\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:image {\"id\":2502,\"width\":\"217px\",\"height\":\"auto\",\"sizeSlug\":\"full\",\"linkDestination\":\"none\"} -->\n<figure class=\"wp-block-image size-full is-resized\"><img src=\"https://dputr.tasikmalayakota.go.id/wp-content/uploads/2025/05/Untitled-design-3.png\" alt=\"\" class=\"wp-image-2502\" style=\"width:217px;height:auto\"/></figure>\n<!-- /wp:image --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:getwid/section {\"skipLayout\":true} -->\n<div class=\"wp-block-getwid-section\"><div class=\"wp-block-getwid-section__wrapper\"><div class=\"wp-block-getwid-section__inner-wrapper\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:columns -->\n<div class=\"wp-block-columns\"><!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Jalan dan Jembatan mempunyai tugas pokok<br>menyelenggarakan penyusunan bahan kebijakan<br>teknis serta menyelenggarakan kegiatan<br>pembangunan, pemeliharaan dan pengelolaan<br>prasarana jalan dan jembatan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column -->\n\n<!-- wp:column -->\n<div class=\"wp-block-column\"><!-- wp:paragraph -->\n<p>Bidang Permukiman mempunyai tugas pokok<br>menyelenggarakan penyusunan kebijakan teknis dan<br>menyelenggarakan kebijakan Bidang Permukiman<br>meliputi pengembangan Permukiman, pengelolaan<br>dan pengembangan sistem air limbah, pengelolaan<br>dan pengembangan sistem penyediaan air minum<br>serta<br>pengembangan sistem dan pengelolaan<br>persampahan.</p>\n<!-- /wp:paragraph --></div>\n<!-- /wp:column --></div>\n<!-- /wp:columns -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1600,\"gapSize\":\"\",\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingRightValue\":\"50%\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1600px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/image-box {\"imageSize\":\"thumbnail\",\"id\":1149,\"textAlignment\":\"left\",\"layout\":\"right\",\"mobileLayout\":\"column\"} -->\n<div class=\"wp-block-getwid-image-box getwid-animation has-image-right has-text-left has-mobile-layout-column has-mobile-alignment-default\" data-animation=\"wobble\"><div class=\"wp-block-getwid-image-box__image-container is-position-top\"><div class=\"wp-block-getwid-image-box__image-wrapper\"><img src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2025/04/Icon.jpeg\" alt=\"\" class=\"wp-block-getwid-image-box__image wp-image-1149\"/></div></div><div class=\"wp-block-getwid-image-box__content\"><!-- wp:getwid/section {\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":567,\"gapSize\":\"\",\"verticalAlign\":\"flex-end\",\"horizontalAlign\":\"flex-start\",\"backgroundImage\":{\"alt\":\"\",\"id\":47,\"url\":\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\"},\"backgroundImagePosition\":\"bottom left\",\"backgroundImageSize\":\"auto\",\"paddingTopValue\":\"90px\",\"paddingBottomValue\":\"90px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\"} -->\n<div class=\"wp-block-getwid-section getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-align-items-flex-end getwid-justify-content-flex-start\" style=\"padding-top:90px;padding-bottom:90px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:567px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:url(\'https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\');background-position:bottom left;background-size:auto\"><div class=\"wp-block-getwid-section__background-image-wrapper\"><img class=\"wp-block-getwid-section__background-image\" src=\"https://dputr.tasikmalayakota.go.id/wordpress/wp-content/uploads/2019/04/home_about_points.png\" alt=\"\"/></div></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"fontFamily\":\"Work Sans\",\"fontSize\":\"24px\",\"fontWeight\":\"200\",\"lineHeight\":\"1em\",\"letterSpacing\":\"0px\",\"marginBottom\":\"5px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:24px;margin-bottom:5px\"><span class=\"wp-block-getwid-advanced-heading__content\" style=\"font-family:&quot;Work Sans&quot;;font-weight:200;line-height:1em;letter-spacing:0px\">Temukan lebih </span></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/advanced-heading {\"titleTag\":\"h3\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"30px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:30px\"><h3 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">Frequently Asked Questions</h3></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Masih punya pertanyaan? pelajari lebih tentang pelayanan kami pada FAQ dibawah ini</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:getwid/advanced-spacer {\"height\":\"20px\"} -->\n<div class=\"wp-block-getwid-advanced-spacer\" style=\"height:20px\" aria-hidden=\"true\"></div>\n<!-- /wp:getwid/advanced-spacer -->\n\n<!-- wp:getwid/toggle {\"iconPosition\":\"right\",\"headerTag\":\"h6\"} -->\n<div class=\"wp-block-getwid-toggle\"><!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Bagaimana cara mengurus Sertifikat layak fungsi (Self) atau Persetujuan Bangunan Gedung (PBG)?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li> Anda dapat mengajukan permohonan   melalui sistem OSS (Online Single Submission)</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Syarat umum: dokumen kepemilikan tanah, gambar teknis bangunan, KTP pemohon, dan pernyataan kesesuaian tata ruang.</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apa yang dimaksud dengan Kesesuaian Kegiatan Pemanfaatan Ruang (KKPR)?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write headingâ¦\"} -->\n<p>KKPR adalah dokumen perizinan yang menyatakan bahwa suatu kegiatan/usaha sesuai dengan rencana tata ruang wilayah setempat.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Bagaimana cara mengetahui apakah tanah saya masuk kawasan yang boleh dibangun?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Anda perlu memeriksa <strong>Rencana Tata Ruang Wilayah (RTRW)</strong> atau <strong>RDTR (Rencana Detail Tata Ruang)</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bisa dicek melalui Mall Pelayanan Publik yang ada di Bale Kota di bagian loket Dinas Pekerjaan Umum dan Tata Ruang</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Siapa yang bertanggung jawab atas saluran drainase yang tersumbat?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Tergantung Lokasi<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Drainase lingkungan: tanggung jawab warga/pemkot dalam hal ini adalah Dinas Pekerjaan Umum dan Tata Ruang bidang Sumber Daya Air</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Drainase utama: Dinas Pekerjaan Umum dan Tata Ruang bidang sumber daya air</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apakah Dinas Pekerjaan Umum dan Tata Ruang bisa membantu penyediaan air bersih</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:paragraph {\"placeholder\":\"Write textâ¦\"} -->\n<p>Dinas Pekerjaan  Umum dan Tata Ruang  bertanggung jawab dalam pengelolaan jaringan air baku dan sanitasi, sementara distribusi air bersih biasanya oleh PDAM.</p>\n<!-- /wp:paragraph --></div></div></div>\n<!-- /wp:getwid/toggle-item -->\n\n<!-- wp:getwid/toggle-item -->\n<div class=\"wp-block-getwid-toggle__row\"><div class=\"wp-block-getwid-toggle__header-wrapper\"><span class=\"wp-block-getwid-toggle__header\"><a href=\"#\"><span class=\"wp-block-getwid-toggle__header-title\">Apa peran Dinas Pekerjaan Umum dan Tata Ruang dalam pembangunan infrastruktur?</span><span class=\"wp-block-getwid-toggle__icon is-active\"><i class=\"fas fa-plus\"></i></span><span class=\"wp-block-getwid-toggle__icon is-passive\"><i class=\"fas fa-minus\"></i></span></a></span></div><div class=\"wp-block-getwid-toggle__content-wrapper\"><div class=\"wp-block-getwid-toggle__content\"><!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>DPUTR bertanggung jawab atas perencanaan, pelaksanaan, dan pengawasan pembangunan infrastruktur seperti:<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Jalan dan jembatan</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Irigasi dan drainase</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Permukiman</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Penataan ruang dan pengendalian bangunan</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></div></div></div>\n<!-- /wp:getwid/toggle-item --></div>\n<!-- /wp:getwid/toggle --></div></div></div></div></div>\n<!-- /wp:getwid/section --></div></div>\n<!-- /wp:getwid/image-box --></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:getwid/section {\"align\":\"full\",\"skipLayout\":true,\"contentMaxWidthPreset\":\"custom\",\"contentMaxWidth\":1130,\"gapSize\":\"\",\"backgroundGradientFirstColor\":\"#f7fbfe\",\"backgroundGradientSecondColor\":\"#ffffff\",\"backgroundGradientType\":\"linear\",\"paddingTopValue\":\"120px\",\"paddingBottomValue\":\"70px\",\"paddingTop\":\"custom\",\"paddingBottom\":\"custom\",\"paddingLeft\":\"large\",\"paddingRight\":\"large\",\"paddingLeftMobile\":\"medium\",\"paddingRightMobile\":\"medium\",\"className\":\"alignfull\"} -->\n<div class=\"wp-block-getwid-section alignfull alignfull getwid-section-content-custom-width\"><div class=\"wp-block-getwid-section__wrapper getwid-padding-left-large getwid-padding-right-large getwid-padding-mobile-left-medium getwid-padding-mobile-right-medium\" style=\"padding-top:120px;padding-bottom:70px\"><div class=\"wp-block-getwid-section__inner-wrapper\" style=\"max-width:1130px\"><div class=\"wp-block-getwid-section__background-holder\"><div class=\"wp-block-getwid-section__background\" style=\"background-image:linear-gradient(180deg,rgba(247,251,254) 0%,rgba(255,255,255) 100%)\"></div><div class=\"wp-block-getwid-section__foreground\"></div></div><div class=\"wp-block-getwid-section__content\"><div class=\"wp-block-getwid-section__inner-content\"><!-- wp:getwid/advanced-heading {\"titleTag\":\"h2\",\"fontSize\":\"33px\",\"fontWeight\":\"\",\"lineHeight\":\"1em\",\"marginBottom\":\"50px\"} -->\n<div class=\"wp-block-getwid-advanced-heading has-custom-font-size\" style=\"font-size:33px;margin-bottom:50px\"><h2 class=\"wp-block-getwid-advanced-heading__content\" style=\"line-height:1em\">INFORMASI</h2></div>\n<!-- /wp:getwid/advanced-heading -->\n\n<!-- wp:getwid/recent-posts {\"imageSize\":\"post-thumbnail\",\"cropImages\":false,\"categories\":\"49\",\"postsToShow\":3,\"showContent\":true,\"contentLength\":23,\"showFeaturedImage\":true,\"postLayout\":\"grid\"} /--></div></div></div></div></div>\n<!-- /wp:getwid/section -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->', 'Home', '', 'inherit', 'closed', 'closed', '', '2404-revision-v1', '', '', '2025-08-11 04:00:04', '2025-08-11 04:00:04', '', 2404, 'https://dputr.tasikmalayakota.go.id/?p=2774', 0, 'revision', '', 0),
